B.a1f=s(["Sit comfortably with your spine straight.","Close your right nostril with your right thumb and inhale through the left nostril.","Close the left nostril with your ring finger and exhale through the right nostril.","Inhale through the right nostril.","Switch again and exhale through the left nostril.","This completes one round. Continue slowly."],t.s)
B.adu=new A.kd("nadi_shodhana","Nadi Shodhana","Alternate nostril breathing for balance.","6-8 min",B.u,"Nadi Shodhana is a gentle breathing practice that involves alternating the breath between the left and right nostrils. It helps reduce stress, improve focus, and bring mental clarity.",B.a1f,"Balances the nervous system and calms the mind.",null,null,"https://www.youtube.com/watch?v=n7dDoXEVLU0")
B.Xe=s(["Sit comfortably and close your eyes.","Inhale deeply through the nose.","Exhale slowly while making a gentle humming sound.","Feel the vibration in your head and chest.","Repeat in a relaxed manner."],t.s)
B.adn=new A.kd("bhramari","Bhramari","Humming breath to calm the nervous system.","4-6 min",B.cG,"Bhramari involves producing a soft humming sound during exhalation. The vibration helps soothe the mind and release mental tension.",B.Xe,"Calms the nervous system and reduces anxiety.",null,null,"https://www.youtube.com/watch?v=Q3Y-aYucA8c")
B.a_k=s(["Sit comfortably or lie down.","Inhale slowly through the nose while slightly tightening the throat.","Exhale through the nose with the same gentle throat contraction.","Maintain a smooth, steady rhythm.","Keep the breath slow and controlled."],t.s)
B.adt=new A.kd("ujjayi","Ujjayi","Ocean breath to deepen focus.","5-7 min",B.aD,"Ujjayi breathing is performed by gently constricting the throat, creating a soft ocean-like sound. It is commonly used to enhance concentration and regulate breath.",B.a_k,"Deepens focus and promotes steady awareness.",null,null,"https://www.youtube.com/watch?v=U6GV_qC32f8")
B.a2m=s(["Sit upright with hands resting on knees.","Take a deep inhale.","Forcefully exhale through the nose by contracting the abdomen.","Allow inhalation to happen naturally.","Continue in short, rhythmic bursts."],t.s)
B.ado=new A.kd("kapalabhati","Kapalabhati","Cleansing breath for energy.","3-5 min",B.dn,"Kapalabhati is a cleansing technique involving rapid, forceful exhalations and passive inhalations. It stimulates energy and clears the respiratory system.",B.a2m,"Energizes the body and improves digestion.",null,null,"https://www.youtube.com/watch?v=k3PU0AM7X8M")
